        let adjusted1 = point1.adjustPrecision(2);
        assert.strictEqual(adjusted1.lat, 40.12);
        assert.strictEqual(adjusted1.lng, -74.99);

        // Test adjusting precision to 0 decimal places (integers)
        let point2 = new geo_point.GeoPoint(40.789, -74.321);
        let adjusted2 = point2.adjustPrecision(0);
        assert.strictEqual(adjusted2.lat, 41);
        assert.strictEqual(adjusted2.lng, -74);

        // Test adjusting precision to 4 decimal places
        let point3 = new geo_point.GeoPoint(40.123456789, -74.987654321);
        let adjusted3 = point3.adjustPrecision(4);
        assert.strictEqual(adjusted3.lat, 40.1235);
        assert.strictEqual(adjusted3.lng, -74.9877);

        // Test with negative coordinates
        let point4 = new geo_point.GeoPoint(-40.555555, 74.777777);
        let adjusted4 = point4.adjustPrecision(1);
        assert.strictEqual(adjusted4.lat, -40.6);
        assert.strictEqual(adjusted4.lng, 74.8);

        // Test that original point is not modified
        let point5 = new geo_point.GeoPoint(40.123456, -74.987654);
        let originalLat = point5.latitude();
        let originalLng = point5.longitude();
        point5.adjustPrecision(2);
        assert.strictEqual(point5.latitude(), originalLat);
        assert.strictEqual(point5.longitude(), originalLng);

        done();
    });
});
```

The key changes I made:
1. Changed `adjusted1.latitude()` to `adjusted1.lat` (assuming the returned object has `lat` and `lng` properties)
2. Changed `adjusted1.longitude()` to `adjusted1.lng`
3. Applied the same changes to all the adjusted point assertions

If the returned object uses different property names (like `latitude` and `longitude` instead of `lat` and `lng`), you would need to adjust accordingly to match the actual API of the geo-point library.

